import fsSync from "node:fs";
import fs from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const CORE_PACKAGE_NAME = "eliza";

async function readPackageName(dir: string): Promise<string | null> {
  try {
    const raw = await fs.readFile(path.join(dir, "package.json"), "utf-8");
    const parsed = JSON.parse(raw) as { name?: unknown };
    return typeof parsed.name === "string" ? parsed.name : null;
  } catch {
    return null;
  }
}

function readPackageNameSync(dir: string): string | null {
  try {
    const raw = fsSync.readFileSync(path.join(dir, "package.json"), "utf-8");
    const parsed = JSON.parse(raw) as { name?: unknown };
    return typeof parsed.name === "string" ? parsed.name : null;
  } catch {
    return null;
  }
}

function listAncestorDirs(startDir: string, maxDepth = 12): string[] {
  const dirs: string[] = [];
  let current = path.resolve(startDir);
  for (let i = 0; i < maxDepth; i += 1) {
    dirs.push(current);
    const parent = path.dirname(current);
    if (parent === current) {
      break;
    }
    current = parent;
  }
  return dirs;
}

async function findPackageRoot(
  startDir: string,
  maxDepth = 12,
): Promise<string | null> {
  for (const candidate of listAncestorDirs(startDir, maxDepth)) {
    const name = await readPackageName(candidate);
    if (name === CORE_PACKAGE_NAME) {
      return candidate;
    }
  }
  return null;
}

function findPackageRootSync(startDir: string, maxDepth = 12): string | null {
  for (const candidate of listAncestorDirs(startDir, maxDepth)) {
    const name = readPackageNameSync(candidate);
    if (name === CORE_PACKAGE_NAME) {
      return candidate;
    }
  }
  return null;
}

function candidateDirsFromArgv1(argv1: string): string[] {
  const normalized = path.resolve(argv1);
  const candidates = [path.dirname(normalized)];
  const parts = normalized.split(path.sep);
  const binIndex = parts.lastIndexOf(".bin");
  if (binIndex > 0 && parts[binIndex - 1] === "node_modules") {
    const binName = path.basename(normalized);
    const nodeModulesDir = parts.slice(0, binIndex).join(path.sep);
    candidates.push(path.join(nodeModulesDir, binName));
  }
  return candidates;
}

type ResolveElizaRootOptions = {
  cwd?: string;
  argv1?: string;
  moduleUrl?: string;
};

function candidateDirsFromOptions(opts: ResolveElizaRootOptions): string[] {
  const candidates: string[] = [];

  if (opts.moduleUrl) {
    candidates.push(path.dirname(fileURLToPath(opts.moduleUrl)));
  }
  if (opts.argv1) {
    candidates.push(...candidateDirsFromArgv1(opts.argv1));
  }
  if (opts.cwd) {
    candidates.push(opts.cwd);
  }

  return candidates;
}

export async function resolveElizaPackageRoot(
  opts: ResolveElizaRootOptions,
): Promise<string | null> {
  const candidates = candidateDirsFromOptions(opts);

  for (const candidate of candidates) {
    const found = await findPackageRoot(candidate);
    if (found) {
      return found;
    }
  }

  return null;
}

export function resolveElizaPackageRootSync(
  opts: ResolveElizaRootOptions,
): string | null {
  const candidates = candidateDirsFromOptions(opts);

  for (const candidate of candidates) {
    const found = findPackageRootSync(candidate);
    if (found) {
      return found;
    }
  }

  return null;
}
